safe_example:
// SAFE: execFile with explicit argument array, no shell invocation
const { execFile } = require('child_process');
const path = require('path');

const ALLOWED_DIRS = ['/opt/reports', '/opt/exports'];

app.get('/list', (req, res) => {
  const dir = path.resolve(req.query.dir);
  if (!ALLOWED_DIRS.some(allowed => dir.startsWith(allowed))) {
    return res.status(400).send('Directory not allowed');
  }
  execFile('ls', ['-la', dir], (err, stdout) => {
    if (err) return res.status(500).send('Error listing directory');
    res.type('text/plain').send(stdout);
  });
});
